import { User } from './types';

export function processData(user: User): string {
  return `User: ${user.name} (${user.email})`;
}

export function validateEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}
