import { User } from './types';

export class UserModel {
  private user: User;

  constructor(user: User) {
    this.user = user;
  }

  getDisplayName(): string {
    return this.user.name;
  }

  isValid(): boolean {
    return this.user.id > 0 && this.user.email.includes('@');
  }
}
